 1	import React from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import EnvironmentForm from '@kubevirt-utils/components/EnvironmentEditor/EnvironmentForm';
 5	import Loading from '@kubevirt-utils/components/Loading/Loading';
 6	import { getDataVolumeTemplates, getDisks, getVolumes } from '@kubevirt-utils/resources/vm';
 7	import {
 8	  updateCustomizeInstanceType,
 9	  updateVMCustomizeIT,
10	  vmSignal,
11	} from '@kubevirt-utils/store/customizeInstanceType';
12	import { Divider, Grid, GridItem, PageSection, PageSectionVariants } from '@patternfly/react-core';
13	import DiskList from '@virtualmachines/details/tabs/configuration/storage/components/tables/disk/DiskList';
14	
15	const CustomizeInstanceTypeStorageTab = () => {
16	  const vm = vmSignal.value;
17	
18	  if (!vm) {
19	    return <Loading />;
20	  }
21	
22	  return (
23	    <Grid hasGutter>
24	      <GridItem>
25	        <PageSection variant={PageSectionVariants.light}>
26	          <DiskList
27	            onDiskUpdate={(updatedVM: V1VirtualMachine) => {
28	              const vmModified = updateCustomizeInstanceType([
29	                {
30	                  data: getDisks(updatedVM),
31	                  path: `spec.template.spec.domain.devices.disks`,
32	                },
33	                {
34	                  data: getVolumes(updatedVM),
35	                  path: `spec.template.spec.volumes`,
36	                },
37	                {
38	                  data: getDataVolumeTemplates(updatedVM),
39	                  path: `spec.dataVolumeTemplates`,
40	                },
41	              ]);
42	
43	              return Promise.resolve(vmModified);
44	            }}
45	            customize
46	            vm={vm}
47	          />
48	        </PageSection>
49	      </GridItem>
50	      <GridItem>
51	        <Divider />
52	      </GridItem>
53	      <GridItem>
54	        <PageSection variant={PageSectionVariants.light}>
55	          <EnvironmentForm updateVM={updateVMCustomizeIT} vm={vm} />
56	        </PageSection>
57	      </GridItem>
58	    </Grid>
59	  );
60	};
61	
62	export default CustomizeInstanceTypeStorageTab;

